import{_ as a,H as i,f as e,i as n}from"./chunks/framework.DbTCwA-u.js";const d=JSON.parse('{"title":"Global Configuration","description":"Learn how to configure EligiusNametag globally via config.yml.","frontmatter":{"title":"Global Configuration","description":"Learn how to configure EligiusNametag globally via config.yml."},"headers":[],"relativePath":"config/global.md","filePath":"config/global.md"}'),t={name:"config/global.md"};function l(o,s,h,p,r,k){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="global-configuration-config-yml" tabindex="-1">Global Configuration (config.yml) <a class="header-anchor" href="#global-configuration-config-yml" aria-label="Permalink to &quot;Global Configuration (config.yml)&quot;">​</a></h1><p>The <code>config.yml</code> file is the brain of the plugin. It controls how the plugin interacts with your server on a macro level, affecting all players equally.</p><hr><h2 id="🛠️-interface-variables" tabindex="-1">🛠️ Interface Variables <a class="header-anchor" href="#🛠️-interface-variables" aria-label="Permalink to &quot;🛠️ Interface Variables&quot;">​</a></h2><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Hologram height above the player&#39;s head</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Recommended: 0.35 for humans, 0.50 if using skins with large hats.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">y_offset</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.35</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Maximum view distance in blocks</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Lower values can improve client performance.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">view_distance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">64</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Main command aliases</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># All of these will execute the help menu or nested commands.</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">command_aliases</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;enametag&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;eltag&quot;</span></span></code></pre></div><hr><h2 id="💾-database-connection-hikaricp" tabindex="-1">💾 Database Connection (HikariCP) <a class="header-anchor" href="#💾-database-connection-hikaricp" aria-label="Permalink to &quot;💾 Database Connection (HikariCP)&quot;">​</a></h2><p>Unlike basic plugins that save preferences in text files, EligiusNametag allows seamless concurrent flow using the industry standard <code>HikariCP</code> to prevent performance drops (Lag Spikes) during massive saves on huge Folia networks.</p><h3 id="🔹-option-a-sqlite-local" tabindex="-1">🔹 Option A: SQLite (Local) <a class="header-anchor" href="#🔹-option-a-sqlite-local" aria-label="Permalink to &quot;🔹 Option A: SQLite (Local)&quot;">​</a></h3><p>Ideal for single servers (isolated Survival, Skyblock). Requires no external configuration. A <code>database.db</code> file will automatically be created in the plugin folder.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">database</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SQLITE&quot;</span></span></code></pre></div><h3 id="🔹-option-b-mysql-velocity-bungee-networks" tabindex="-1">🔹 Option B: MySQL (Velocity/Bungee Networks) <a class="header-anchor" href="#🔹-option-b-mysql-velocity-bungee-networks" aria-label="Permalink to &quot;🔹 Option B: MySQL (Velocity/Bungee Networks)&quot;">​</a></h3><p>Ideal if you own multiple connected servers and want the <code>/enametag me</code> command preference (show or hide your nametag) to travel with the player from one server to another.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">database</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;MYSQL&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  mysql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    host</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;127.0.0.1&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3306</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    database</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;eligius_network&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    username</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;admin&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    password</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;super_secure_password&quot;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">⚠️ IMPORTANT REGARDING MYSQL</p><p>Ensure that the <code>eligius_network</code> database already exists on your MySQL/MariaDB server before turning on the plugin. The plugin will create the tables internally, but cannot create the root database for security reasons.</p></div>`,15)])])}const g=a(t,[["render",l]]);export{d as __pageData,g as default};
